arguments.content:
:root {
    --bg-color: #0f172a;
    --card-bg: #1e293b;
    --text-primary: #f8fafc;
    --text-secondary: #94a3b8;
    --accent-color: #38bdf8;
    --success-color: #22c55e;
    --warning-color: #f59e0b;
    --danger-color: #ef4444;
}

body {
    margin: 0;
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background-color: var(--bg-color);
    color: var(--text-primary);
    display: flex;
    justify-content: center;
    min-height: 100vh;
}

.container {
    width: 90%;
    max-width: 1200px;
    padding: 2rem 0;
}

header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
    border-bottom: 1px solid var(--card-bg);
    padding-bottom: 1rem;
}

h1 {
    margin: 0;
    font-size: 1.8rem;
    background: linear-gradient(to right, var(--accent-color), #818cf8);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

#status-indicator {
    font-size: 0.875rem;
    padding: 0.25rem 0.75rem;
    border-radius: 9999px;
    background-color: rgba(34, 197, 94, 0.1);
    color: var(--success-color);
}

#status-indicator.status-online {
    color: var(--success-color);
}

#status-indicator.status-offline {
    color: var(--danger-color);
    background-color: rgba(239, 68, 68, 0.1);
}

main {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(450px, 1fr));
    gap: 1.5rem;
}

.chart-card {
    background-color: var(--card-bg);
    border-radius: 0.75rem;
    padding: 1.5rem;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
}

h2 {
    margin-top: 0;
    font-size: 1.25rem;
    color: var(--text-secondary);
    margin-bottom: 1.5rem;
}

.chart-container {
    position: relative;
    height: 300px;
    width: 100%;
}

footer {
    margin-top: 3rem;
    text-align: center;
    color: var(--text-secondary);
    font-size: 0.875rem;
}

@media (max-width: 600px) {
    main {
        grid-template-columns: 1fr;
    }
}

const USAGE_CHART_ID = 'usageChart';
const TEMP_CHART_ID = 'tempChart';
const UPDATE_INTERVAL = 10000; // 10 seconds

let usageChart;
let tempChart;

/**
 * Initializes the charts.
 */
function initCharts() {
    const usageCtx = document.getElementById(USAGE_CHART_ID).getContext('2d');
    usageChart = new Chart(usageCtx, {
        type: 'line',
        data: {
            labels: [],
            datasets: [
                {
                    label: 'CPU Usage (%)',
                    borderColor: '#38bdf8',
                    backgroundColor: 'rgba(56, 189, 248, 0.1)',
                    data: [],
                    fill: true,
                    tension: 0.4
                },
                {
                    label: 'Memory Usage (%)',
                    borderColor: '#818cf8',
                    backgroundColor: 'rgba(129, 140, 248, 0.1)',
                    data: [],
                    fill: true,
                    tension: 0.4
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: true,
                    max: 100,
                    grid: { color: 'rgba(148, 163, 184, 0.1)' },
                    ticks: { color: '#94a3b8' }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: '#94a3b8' }
                }
            },
            plugins: {
                legend: {
                    labels: { color: '#f8fafc' }
                }
            }
        }
    });

    const tempCtx = document.getElementById(TEMP_CHART_ID).getContext('2d');
    tempChart = new Chart(tempCtx, {
        type: 'line',
        data: {
            labels: [],
            datasets: [
                {
                    label: 'CPU Temp (°C)',
                    borderColor: '#f87171',
                    backgroundColor: 'rgba(248, 113, 113, 0.1)',
                    data: [],
                    fill: true,
                    tension: 0.4
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: false,
                    grid: { color: 'rgba(148, 163, 184, 0.1)' },
                    ticks: { color: '#94a3b8' }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: '#94a3b8' }
                }
            },
            plugins: {
                legend: {
                    labels: { color: '#f8fafc' }
                }
            }
        }
    });
}

/**
 * Calculates the average CPU temperature from thermal data.
 * @param {Object} thermalData 
 * @returns {number|null}
 */
function calculateAvgCpuTemp(thermalData) {
    if (!thermalData || Object.keys(thermalData).length === 0) {
        return null;
    }

    const temps = Object.values(thermalData);
    const sum = temps.reduce((a, b) => a + b, 0);
    return sum / temps.length;
}

/**
 * Fetches metrics from the API and updates charts.
 */
async function updateDashboard() {
    const statusIndicator = document.getElementById('status-indicator');

    try {
        const response = await fetch('/api/metrics');
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();

        // Update status
        statusIndicator.textContent = 'Online';
        statusIndicator.className = 'status-online';

        if (data.length === 0) return;

        // Extract labels (using timestamp if it existed, otherwise index)
        // For now, we'll just use the index as the label
        const labels = data.map((_, index) => index);

        // Update Usage Chart
        usageChart.data.labels = labels;
        usageChart.data.datasets[0].data = data.map(m => m.cpu_percent);
        usageChart.data.datasets[1].data = data.map(m => m.memory_percent);
        usageChart.update('none'); // Use 'none' for better performance

        // Update Temp Chart
        tempChart.data.labels = labels;
        tempChart.data.datasets[0].data = data.map(m => calculateAvgCpuTemp(m.thermal_data));
        tempChart.update('none');

    } catch (error) {
        console.error('Failed to fetch metrics:', error);
        statusIndicator.textContent = 'Offline';
        statusIndicator.className = 'status-offline';
    }
}

// Start the application
document.addEventListener('DOMContentLoaded', () => {
    initCharts();
    updateDashboard();
    setInterval(updateDashboard, UPDATE_INTERVAL);
});
